module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam S0 = 2'b00;
localparam S1 = 2'b01;
localparam S2 = 2'b10;
localparam S3 = 2'b11;

reg [1:0] state, next_state;

always @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
        state <= S0;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    case (state)
        S0: begin
            next_state = (data_in == 0) ? S1 : S0;
        end
        S1: begin
            next_state = (data_in == 1) ? S2 : S1;
        end
        S2: begin
            next_state = (data_in == 0) ? S3 : S0;
        end
        S3: begin
            next_state = (data_in == 1) ? S2 : S1;
        end
        default: begin
            next_state = S0;
        end
    endcase
end

always @(*) begin
    data_out = (state == S2) & (data_in == 0);
end

endmodule
